const items = $input.all();

function parseWav(buffer) {
  const sampleRate = buffer.readUInt32LE(24);
  const numChannels = buffer.readUInt16LE(22);
  const bitsPerSample = buffer.readUInt16LE(34);
  const dataSize = buffer.readUInt32LE(40);
  const pcmData = buffer.slice(44, 44 + dataSize);
  return { sampleRate, numChannels, bitsPerSample, pcmData };
}

function buildWavHeader(totalDataSize, sampleRate, numChannels, bitsPerSample) {
  const header = Buffer.alloc(44);
  const byteRate = sampleRate * numChannels * bitsPerSample / 8;
  const blockAlign = numChannels * bitsPerSample / 8;
  header.write('RIFF', 0);
  header.writeUInt32LE(36 + totalDataSize, 4);
  header.write('WAVE', 8);
  header.write('fmt ', 12);
  header.writeUInt32LE(16, 16);
  header.writeUInt16LE(1, 20);
  header.writeUInt16LE(numChannels, 22);
  header.writeUInt32LE(sampleRate, 24);
  header.writeUInt32LE(byteRate, 28);
  header.writeUInt16LE(blockAlign, 32);
  header.writeUInt16LE(bitsPerSample, 34);
  header.write('data', 36);
  header.writeUInt32LE(totalDataSize, 40);
  return header;
}

const pcmChunks = [];
let format = null;

for (let i = 0; i < items.length; i++) {
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  const parsed = parseWav(buffer);

  if (!format) {
    format = {
      sampleRate: parsed.sampleRate,
      numChannels: parsed.numChannels,
      bitsPerSample: parsed.bitsPerSample
    };
  }
  pcmChunks.push(parsed.pcmData);
}

const totalPcm = Buffer.concat(pcmChunks);
const header = buildWavHeader(
  totalPcm.length,
  format.sampleRate,
  format.numChannels,
  format.bitsPerSample
);
const finalWav = Buffer.concat([header, totalPcm]);

return [{
  json: { fileName: 'podcast.wav', sizeBytes: finalWav.length },
  binary: {
    data: await this.helpers.prepareBinaryData(finalWav, 'podcast.wav', 'audio/wav')
  }
}];
